import React from 'react';
import { FormData, Category, ShirtVersion } from '../types';
import { categories } from '../constants';
import { getProductName, getImagePath, getShirtVersionTotal } from '../utils';

interface ReceiptPageProps {
  formData: FormData;
}

const ReceiptPage: React.FC<ReceiptPageProps> = ({ formData }) => {
  return (
    <div style={{ background: '#fff', minHeight: '100vh', padding: 'var(--space-3)', fontFamily: 'monospace' }}>
      <h1 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-3)', textAlign: 'center' }}>Order Receipt</h1>
      <div style={{ maxWidth: 500, margin: '0 auto', border: '1px solid #ccc', borderRadius: 'var(--radius)', padding: 'var(--space-3)', background: '#fafafa' }}>
        <div style={{ marginBottom: '1rem' }}><strong>Store Number:</strong> {formData.storeNumber}</div>
        <div style={{ marginBottom: '1rem' }}><strong>Store Manager:</strong> {formData.storeManager}</div>
        <div style={{ marginBottom: '2rem' }}><strong>Date:</strong> {formData.date}</div>
        {categories.map((category: Category) => (
          <div key={category.name} style={{ marginBottom: '1.5rem' }}>
            <div style={{ fontWeight: 'bold', borderBottom: '1px solid #ccc', marginBottom: 4 }}>{category.name}</div>
            {category.images.map((img) => {
              const imagePath = getImagePath(category.path, img);
              const productName = getProductName(img);

              if (category.hasShirtVersions) {
                const shirtVersions = formData.shirtVersions?.[imagePath];
                const totalQty = getShirtVersionTotal(shirtVersions);

                if (totalQty > 0) {
                  return (
                    <div key={img} style={{ marginBottom: '0.5rem' }}>
                      <div style={{ fontWeight: 'bold', fontSize: 14 }}>{productName}</div>
                      {shirtVersions?.tshirt && Number(shirtVersions.tshirt) > 0 && (
                        <div style={{ display: 'flex', justifyContent: 'space-between', padding: '1px 0', fontSize: 13, marginLeft: '1rem' }}>
                          <span>T-Shirt</span>
                          <span>Qty: {shirtVersions.tshirt}</span>
                        </div>
                      )}
                      {shirtVersions?.longsleeve && Number(shirtVersions.longsleeve) > 0 && (
                        <div style={{ display: 'flex', justifyContent: 'space-between', padding: '1px 0', fontSize: 13, marginLeft: '1rem' }}>
                          <span>Long Sleeve</span>
                          <span>Qty: {shirtVersions.longsleeve}</span>
                        </div>
                      )}
                      {shirtVersions?.hoodie && Number(shirtVersions.hoodie) > 0 && (
                        <div style={{ display: 'flex', justifyContent: 'space-between', padding: '1px 0', fontSize: 13, marginLeft: '1rem' }}>
                          <span>Hoodie</span>
                          <span>Qty: {shirtVersions.hoodie}</span>
                        </div>
                      )}
                      <div style={{ display: 'flex', justifyContent: 'space-between', padding: '1px 0', fontSize: 13, marginLeft: '1rem', fontWeight: 'bold' }}>
                        <span>Total</span>
                        <span>Qty: {totalQty}</span>
                      </div>
                    </div>
                  );
                }
                return null; // Don't show items with 0 quantity
              } else {
                const qty = formData.quantities[imagePath] || '0';
                if (Number(qty) > 0) {
                  return (
                    <div key={img} style={{ display: 'flex', justifyContent: 'space-between', padding: '2px 0', fontSize: 15 }}>
                      <span>{productName}</span>
                      <span>Qty: {qty}</span>
                    </div>
                  );
                }
                return null; // Don't show items with 0 quantity
              }
            })}
          </div>
        ))}
      </div>
    </div>
  );
};

export default ReceiptPage;
